                                                    className="px-3 py-1 bg-gray-100 text-gray-600 text-xs rounded-full hover:bg-gray-200 transition-colors duration-200 cursor-pointer"
                                                >
                                                    #{tag}
                                                </span>
                                            ))}
                                        </div>

                                        {/* Author and Actions */}
                                        <div className="flex items-center justify-between pt-4 border-t border-gray-100">
                                            <span className="text-sm text-gray-500 flex items-center gap-1">
                                                <span className="material-icons text-sm">person</span>
                                                {item.author}
                                            </span>
                                            <div className="flex items-center gap-3">
                                                <button
                                                    onClick={() => toggleLike(item.id)}
                                                    className={`transition-all duration-300 ${likedItems[item.id] ? 'text-red-500 scale-110' : 'text-gray-400 hover:text-red-500'}`}
                                                >
                                                    <span className="material-icons text-xl">
                                                        {likedItems[item.id] ? 'favorite' : 'favorite_border'}
                                                    </span>
                                                </button>
                                                <a 
                                                    href={item.fullContent} 
                                                    className="inline-flex items-center gap-1 text-blue-600 font-medium hover:text-blue-700 transition-all duration-300 group/link"
                                                >
                                                    <span className="text-sm">{t('newsPage.buttons.readMore')}</span>
                                                    <span className="material-icons text-lg transform group-hover/link:translate-x-1 transition-transform duration-300">
                                                        arrow_forward
                                                    </span>
                                                </a>
                                            </div>
                                        </div>
                                    </div>
                                </div>
                            </div>
                        ))}
                    </div>

                    {/* No Results with Animation */}
                    {filteredNews.length === 0 && (
                        <div className="text-center py-20 animate-fade-in">
                            <div className="inline-flex items-center justify-center w-24 h-24 bg-gradient-to-br from-gray-100 to-gray-200 rounded-full mb-6">
                                <span className="material-icons text-4xl text-gray-400">search_off</span>
                            </div>
                            <h3 className="text-2xl font-semibold text-gray-900 mb-2">
                                {t('newsPage.noResults.title')} {activeCategory === 'all' ? t('newsPage.noResults.items') : getCategoryLabel(activeCategory)}
                            </h3>
                            <p className="text-gray-600">{t('newsPage.noResults.description')}</p>
                        </div>
                    )}
                </div>
            </section>

            {/* Light & Animated Campus Life Section */}
            <section className="py-20 relative overflow-hidden bg-gradient-to-br from-white via-blue-50/30 to-purple-50/30">
                <div className="absolute inset-0">
                    <div className="absolute top-0 left-1/4 w-96 h-96 bg-blue-200/30 rounded-full blur-3xl animate-float"></div>
                    <div className="absolute bottom-0 right-1/4 w-96 h-96 bg-purple-200/30 rounded-full blur-3xl animate-float-delayed"></div>
                </div>

                <div className="max-w-7xl mx-auto px-4 relative z-10">
                    <div className="text-center mb-16 animate-on-scroll">
                        <div className="inline-flex items-center px-6 py-3 bg-white/80 backdrop-blur-sm rounded-full text-blue-600 text-sm font-semibold mb-4 shadow-lg">
                            <span className="material-icons text-lg mr-2 animate-spin-slow">stars</span>
                            Campus Experience
                        </div>
                        <h2 className="text-5xl font-bold bg-gradient-to-r from-blue-600 via-purple-600 to-pink-600 bg-clip-text text-transparent mb-6 animate-gradient">
                            {t('newsPage.campusLife.title')}
                        </h2>
                        <p className="text-xl text-gray-600 max-w-3xl mx-auto">
                            {t('newsPage.campusLife.subtitle')}
                        </p>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                        {[
                            { icon: 'groups', gradient: 'from-blue-400 to-cyan-400', title: 'studentLife', delay: '0' },
                            { icon: 'sports_esports', gradient: 'from-purple-400 to-pink-400', title: 'clubs', delay: '100' },
                            { icon: 'restaurant', gradient: 'from-green-400 to-emerald-400', title: 'dining', delay: '200' },
                            { icon: 'fitness_center', gradient: 'from-orange-400 to-red-400', title: 'sports', delay: '300' }
                        ].map((item, index) => (
                            <div 
                                key={index}
                                className="animate-on-scroll opacity-0 translate-y-8"
                                style={{ animationDelay: `${item.delay}ms` }}
                            >
                                <div className="group relative bg-white/80 backdrop-blur-sm rounded-3xl p-8 shadow-xl hover:shadow-2xl transition-all duration-500 hover:-translate-y-2 border border-white/50 overflow-hidden">
                                    <div className="absolute top-0 right-0 w-32 h-32 bg-gradient-to-br opacity-10 rounded-full blur-2xl transition-all duration-500 group-hover:scale-150"
                                         style={{ background: `linear-gradient(to bottom right, var(--tw-gradient-stops))` }}
                                         className={`${item.gradient}`}
                                    ></div>
                                    <div className={`relative w-16 h-16 bg-gradient-to-br ${item.gradient} rounded-2xl flex items-center justify-center mb-6 shadow-lg transform transition-all duration-500 group-hover:scale-110 group-hover:rotate-3`}>
                                        <span className="material-icons text-white text-2xl">{item.icon}</span>
                                    </div>
                                    <h3 className="text-2xl font-bold text-gray-900 mb-4 transition-colors duration-300 group-hover:text-transparent group-hover:bg-gradient-to-r group-hover:from-blue-600 group-hover:to-purple-600 group-hover:bg-clip-text">
                                        {t(`newsPage.campusLife.${item.title}.title`)}
                                    </h3>
                                    <p className="text-gray-600 leading-relaxed">
                                        {t(`newsPage.campusLife.${item.title}.description`)}
                                    </p>
                                    <div className={`mt-6 h-1 bg-gradient-to-r ${item.gradient} rounded-full transform scale-x-0 group-hover:scale-x-100 transition-transform duration-500 origin-left`}></div>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
            </section>

            {/* Light & Modern Facilities Section */}
            <section className="py-20 relative overflow-hidden bg-gradient-to-br from-slate-50 via-white to-indigo-50">
                <div className="absolute inset-0">
                    <div className="absolute top-1/4 left-0 w-96 h-96 bg-indigo-200/20 rounded-full blur-3xl animate-pulse-slow"></div>
                    <div className="absolute bottom-1/4 right-0 w-96 h-96 bg-purple-200/20 rounded-full blur-3xl animate-pulse-slow animation-delay-2000"></div>
                </div>

                <div className="max-w-7xl mx-auto px-4 relative z-10">
                    <div className="text-center mb-16 animate-on-scroll">
                        <div className="inline-flex items-center px-6 py-3 bg-white/80 backdrop-blur-sm rounded-full text-indigo-600 text-sm font-semibold mb-4 shadow-lg">
                            <span className="material-icons text-lg mr-2">apartment</span>
                            World-Class Facilities
                        </div>
                        <h2 className="text-5xl font-bold text-gray-900 mb-6">
                            {t('newsPage.facilities.title')}
                        </h2>
                        <p className="text-xl text-gray-600 max-w-3xl mx-auto">
                            {t('newsPage.facilities.subtitle')}
                        </p>
                    </div>

                    <div className="space-y-24">
                        {[
                            { 
                                icon: 'science', 
                                gradient: 'from-blue-400 to-indigo-400',
                                badge: 'Technology Hub',
                                badgeColor: 'bg-blue-100 text-blue-700',
                                title: 'modernLabs',
                                video: data1Video,
                                features: ['ai', 'robotics', 'networking'],
                                pattern: 'dots'
                            },
                            {
                                icon: 'local_library',
                                gradient: 'from-purple-400 to-pink-400',
                                badge: 'Knowledge Center',
                                badgeColor: 'bg-purple-100 text-purple-700',
                                title: 'library',
                                video: data2Video,
                                features: ['books', 'digitalResources', 'studySpaces'],
                                pattern: 'lines',
                                reverse: true
                            },
                            {
                                icon: 'home',
                                gradient: 'from-green-400 to-emerald-400',
                                badge: 'Student Housing',
                                badgeColor: 'bg-green-100 text-green-700',
                                title: 'dormitories',
                                video: data3Video,
                                features: ['furnished', 'wifi', 'communitySpaces'],
                                pattern: 'waves'
                            }
                        ].map((facility, index) => (
                            <div key={index} className={`animate-on-scroll opacity-0 translate-y-8 grid grid-cols-1 lg:grid-cols-2 gap-12 items-center ${facility.reverse ? 'lg:flex-row-reverse' : ''}`}>
                                <div className={`relative group ${facility.reverse ? 'lg:order-2' : ''}`}>
                                    <div className={`absolute -inset-4 bg-gradient-to-r ${facility.gradient} rounded-3xl blur-2xl opacity-20 group-hover:opacity-30 transition-opacity duration-500`}></div>
                                    <div className="relative overflow-hidden rounded-3xl shadow-2xl">
                                        <video autoPlay muted loop className="w-full h-80 object-cover">
                                            <source src={facility.video} type="video/mp4" />
                                            {t('newsPage.videoNotSupported')}
                                        </video>
                                        <div className="absolute inset-0 bg-gradient-to-t from-black/30 to-transparent"></div>
                                        {/* Pattern overlay */}
                                        <div className={`absolute inset-0 opacity-10 ${
                                            facility.pattern === 'dots' ? 'bg-dots' : 
                                            facility.pattern === 'lines' ? 'bg-lines' : 
                                            'bg-waves'
                                        }`}></div>
                                    </div>
                                </div>
                                <div className={`space-y-6 ${facility.reverse ? 'lg:order-1' : ''}`}>
                                    <div className={`inline-flex items-center px-4 py-2 ${facility.badgeColor} rounded-full text-sm font-medium`}>
                                        <span className="material-icons text-lg mr-2">{facility.icon}</span>
                                        {facility.badge}
                                    </div>
                                    <h3 className="text-3xl md:text-4xl font-bold text-gray-900">
                                        {t(`newsPage.facilities.${facility.title}.title`)}
                                    </h3>
                                    <p className="text-lg text-gray-600 leading-relaxed">
                                        {t(`newsPage.facilities.${facility.title}.description`)}
                                    </p>
                                    <div className="space-y-3">
                                        {facility.features.map((feature, fIndex) => (
                                            <div key={fIndex} className="flex items-center text-gray-700 group/item">
                                                <div className={`w-10 h-10 bg-gradient-to-r ${facility.gradient} rounded-lg flex items-center justify-center mr-3 shadow-md transform transition-all duration-300 group-hover/item:scale-110 group-hover/item:rotate-3`}>
                                                    <span className="material-icons text-white text-sm">check</span>
                                                </div>
                                                <span className="text-lg">{t(`newsPage.facilities.${facility.title}.features.${feature}`)}</span>
                                            </div>
                                        ))}
                                    </div>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
            </section>

            {/* Light & Vibrant Niigata Life Section */}
            <section className="py-20 relative overflow-hidden bg-gradient-to-br from-emerald-50 via-white to-cyan-50">
                <div className="absolute inset-0">
                    <div className="absolute top-20 left-20 w-64 h-64 bg-emerald-300/20 rounded-full blur-3xl animate-bounce-slow"></div>
                    <div className="absolute bottom-20 right-20 w-80 h-80 bg-cyan-300/20 rounded-full blur-3xl animate-bounce-slow animation-delay-3000"></div>
                </div>

                <div className="max-w-7xl mx-auto px-4 relative z-10">
                    <div className="text-center mb-16 animate-on-scroll">
                        <div className="inline-flex items-center px-6 py-3 bg-gradient-to-r from-emerald-100 to-cyan-100 rounded-full text-emerald-700 text-sm font-semibold mb-4 shadow-lg">
                            <span className="material-icons text-lg mr-2 animate-pulse">location_city</span>
                            Discover Niigata
                        </div>
                        <h2 className="text-5xl font-bold bg-gradient-to-r from-emerald-600 via-teal-600 to-cyan-600 bg-clip-text text-transparent mb-6 animate-gradient">
                            {t('newsPage.niigataLife.title')}
                        </h2>
                        <p className="text-xl text-gray-600 max-w-3xl mx-auto">
                            {t('newsPage.niigataLife.subtitle')}
                        </p>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8 mb-16">
                        {[
                            { icon: 'landscape', gradient: 'from-emerald-400 to-teal-400', title: 'nature', pattern: 'topography' },
                            { icon: 'ramen_dining', gradient: 'from-orange-400 to-red-400', title: 'culture', pattern: 'japanese' },
                            { icon: 'train', gradient: 'from-blue-400 to-indigo-400', title: 'transportation', pattern: 'circuit' },
                            { icon: 'ac_unit', gradient: 'from-cyan-400 to-blue-400', title: 'seasons', pattern: 'snow' }
                        ].map((item, index) => (
                            <div 
                                key={index}
                                className="animate-on-scroll opacity-0 translate-y-8"
                                style={{ animationDelay: `${index * 100}ms` }}
                            >
                                <div className="group relative bg-white/80 backdrop-blur-sm rounded-3xl p-8 shadow-xl hover:shadow-2xl transition-all duration-500 hover:-translate-y-2 border border-white/50 overflow-hidden">
                                    <div className={`absolute inset-0 opacity-5 ${item.pattern}`}></div>
                                    <div className={`relative w-16 h-16 bg-gradient-to-br ${item.gradient} rounded-2xl flex items-center justify-center mb-6 shadow-lg transform transition-all duration-500 group-hover:scale-110 group-hover:rotate-6`}>
                                        <span className="material-icons text-white text-2xl">{item.icon}</span>
                                    </div>
                                    <h3 className="text-2xl font-bold text-gray-900 mb-4">
                                        {t(`newsPage.niigataLife.${item.title}.title`)}
                                    </h3>
                                    <p className="text-gray-600 leading-relaxed">
                                        {t(`newsPage.niigataLife.${item.title}.description`)}
                                    </p>
                                </div>
                            </div>
                        ))}
                    </div>

                    <div className="bg-white/60 backdrop-blur-lg rounded-3xl p-8 shadow-2xl border border-white/50 animate-on-scroll">
                        <div className="text-center mb-12">
                            <h3 className="text-4xl font-bold bg-gradient-to-r from-gray-900 to-emerald-700 bg-clip-text text-transparent">
                                {t('newsPage.niigataLife.gallery.title')}
                            </h3>
                        </div>
                        <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                            {[
                                { video: data4Video, label: 'cityView', gradient: 'from-blue-400 to-indigo-400' },
                                { video: data5Video, label: 'festivals', gradient: 'from-orange-400 to-red-400' },
                                { video: data6Video, label: 'winterScenes', gradient: 'from-cyan-400 to-blue-400' }
                            ].map((item, index) => (
                                <div key={index} className="group relative overflow-hidden rounded-2xl shadow-xl hover:shadow-2xl transition-all duration-500">
                                    <div className={`absolute inset-0 bg-gradient-to-br ${item.gradient} opacity-0 group-hover:opacity-20 transition-opacity duration-500`}></div>
                                    <video autoPlay muted loop className="w-full h-64 object-cover group-hover:scale-110 transition-transform duration-700">
                                        <source src={item.video} type="video/mp4" />
                                        {t('newsPage.videoNotSupported')}
                                    </video>
                                    <div className="absolute inset-0 bg-gradient-to-t from-black/70 via-transparent to-transparent group-hover:from-black/50 transition-all duration-500"></div>
                                    <div className="absolute bottom-6 left-6 right-6">
                                        <div className="bg-white/20 backdrop-blur-md rounded-xl px-4 py-3 border border-white/30 transform translate-y-2 group-hover:translate-y-0 transition-transform duration-500">
                                            <span className="text-white font-semibold text-lg">{t(`newsPage.niigataLife.gallery.${item.label}`)}</span>
                                        </div>
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>
                </div>
            </section>
        </div>
    );
};

export default NewsPage;
